<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\SharePointService;use App\Services\InspectionPacketService;
final class InspectionArchiveController{
 public function index():void{Auth::requireRole('owner','administrator','office','crew_leader');$rows=Database::connection()->query('SELECT a.*,i.job_id,u.name generated_name FROM inspection_packet_archives a JOIN inspections i ON i.id=a.inspection_id LEFT JOIN users u ON u.id=a.generated_by ORDER BY a.generated_at DESC')->fetchAll();View::render('portal/inspections/archives',['title'=>'Inspection Packet Archive','archives'=>$rows],'portal');}
 public function archive(int $id):void{Auth::requireRole('owner','administrator','office','crew_leader');verify_csrf();$packet=(new InspectionPacketService())->render($id);$filename='inspection-'.$id.'-'.date('Ymd-His').'.pdf';$dir=dirname(__DIR__,2).'/storage/generated/inspections';if(!is_dir($dir))mkdir($dir,0770,true);$path=$dir.'/'.$filename;file_put_contents($path,$packet['bytes']);$pdo=Database::connection();$pdo->prepare('INSERT INTO inspection_packet_archives(inspection_id,filename,local_path,generated_by) VALUES(?,?,?,?)')->execute([$id,$filename,$path,Auth::id()]);$archiveId=(int)$pdo->lastInsertId();$sp=new SharePointService();if($sp->configured()){try{$base=(string)\App\Core\Env::get('M365_SHAREPOINT_BASE_FOLDER','General/Operations Portal');$up=$sp->upload($path,$base.'/Inspection Packets/'.$filename);$pdo->prepare("UPDATE inspection_packet_archives SET storage_status='uploaded',sharepoint_item_id=?,sharepoint_url=? WHERE id=?")->execute([$up['id']??null,$up['webUrl']??null,$archiveId]);}catch(\Throwable $e){$pdo->prepare("UPDATE inspection_packet_archives SET storage_status='failed',upload_error=? WHERE id=?")->execute([$e->getMessage(),$archiveId]);}}flash('success','Inspection packet archived.');redirect('/portal/inspection-archives');}
 public function download(int $id):void{Auth::requireLogin();$q=Database::connection()->prepare('SELECT * FROM inspection_packet_archives WHERE id=?');$q->execute([$id]);$a=$q->fetch();if(!$a||!is_file($a['local_path'])){http_response_code(404);exit('Archive not found');}header('Content-Type: application/pdf');header('Content-Disposition: inline; filename="'.basename($a['filename']).'"');readfile($a['local_path']);exit;}
}
